-- source: V32__release_ios_product_id_alignment.sql
-- 多 App release-gate 商品 ID 对齐配置。
-- 中文说明：统一后端可以复用 App Store 验签和权益投影能力，但每个 App 的商品 ID 必须按 appCode 隔离。
-- release_ios.product_ids 用于上线门禁比对，防止拍拍伴读的 billing productMappings / App Store Connect 商品配置偏离。

UPDATE public.sys_remote_config
SET status = 'inactive', updated_at = now()
WHERE namespace_code = 'release_ios'
  AND config_key = 'product_ids'
  AND app_code = 'paipai_readingcompanion';

-- source: V32__release_ios_product_id_alignment.sql
INSERT INTO public.sys_remote_config (app_code, namespace_code, config_key, config_value_json, status, created_at, updated_at)
VALUES
('paipai_readingcompanion', 'release_ios', 'product_ids', '{"value":["com.paipai.readalong.family.monthly","com.paipai.readalong.family.multi_child.lifetime","com.paipai.readalong.family.yearly"]}', 'active', now(), now());


-- source: V34__multi_app_release_update_policy.sql
-- 多 App 通用 App Store 更新提示配置补齐。
-- 中文说明：
-- 1. 该 namespace 只承载普通版本提示与 App Store 跳转配置，客户端不得硬编码下载地址。
-- 2. appStoreUrl / appStoreId 需要在 App Store Connect 生成真实 App Apple ID 后由生产配置覆盖；
--    未配置真实 URL 时，客户端只展示当前/最新版本，不展示可点击跳转入口。
-- 3. 各 App 使用相同 namespace，但按 app_code 隔离，避免统一后端下跳转到其他 App 的商店页。

UPDATE public.sys_remote_config
SET status = 'inactive', updated_at = now()
WHERE app_code = 'paipai_readingcompanion'
  AND namespace_code = 'app_release_policy';

-- source: V34__multi_app_release_update_policy.sql
INSERT INTO public.sys_remote_config (app_code, namespace_code, config_key, config_value_json, status, created_at, updated_at)
VALUES
('paipai_readingcompanion', 'app_release_policy', 'ios', '{"value":{"version":1,"appName":"拍拍伴读","platform":"ios","latestVersion":"1.0.0","latestBuild":"1","minimumSupportedVersion":"1.0.0","severity":"recommended","blocking":false,"appStoreId":"","appStoreUrl":"","downloadUrl":"","storeUrl":"","updateUrl":"","title":"发现新版本","message":"拍拍伴读有新版本可用。你可以前往 App Store 查看并决定是否更新。","ctaText":"前往 App Store","releaseNotes":["优化陪读体验与稳定性"],"opsNote":"生产环境必须填入本 App 的真实 App Store URL 或 appStoreId；客户端只消费该配置，不在前端硬编码下载地址。"}}', 'active', now(), now());

-- source: V35__sys_entitlement_center_mode3.sql
-- 统一后台式权益中心（模式三：老用户权益保护版）。
-- 中文说明：权益配置按 app_code 隔离，当前仅保留拍拍伴读需要的策略。
-- 设计目标：
-- 1) 免费权益按当前后台配置动态调整；
-- 2) 付费权益在有效期内保留购买时快照，后台降配不能影响已付款承诺；
-- 3) 新增/提升权益自动给有效期内老用户补齐；
-- 4) 人工赠送和用户级覆盖不要写 sys_entitlement_snapshot，避免被 App Store 刷新覆盖。

CREATE TABLE IF NOT EXISTS public.sys_membership_plan (
    id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    app_code varchar(64) NOT NULL,
    plan_code varchar(64) NOT NULL,
    display_name varchar(128) NOT NULL,
    description varchar(512),
    plan_level integer DEFAULT 0 NOT NULL,
    entitlement_code varchar(64),
    status varchar(32) DEFAULT 'active' NOT NULL,
    sort_order integer DEFAULT 0 NOT NULL,
    metadata_json jsonb,
    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL
);

-- source: V35__sys_entitlement_center_mode3.sql
CREATE UNIQUE INDEX IF NOT EXISTS uk_sys_membership_plan_app_plan ON public.sys_membership_plan(app_code, plan_code);

-- source: V35__sys_entitlement_center_mode3.sql
CREATE INDEX IF NOT EXISTS idx_sys_membership_plan_app_status ON public.sys_membership_plan(app_code, status);

-- source: V35__sys_entitlement_center_mode3.sql
